-- ── mart_team_schedule_context  (16 columns) ──
CREATE OR REPLACE EXTERNAL TABLE baseball_data.lakehouse_ext.mart_team_schedule_context (
    GAME_PK                            NUMBER(38,0)   AS (VALUE:game_pk::NUMBER(38,0)),
    GAME_DATE                          DATE           AS (VALUE:game_date::DATE),
    GAME_YEAR                          NUMBER(38,0)   AS (VALUE:game_year::NUMBER(38,0)),
    TEAM_ABBREV                        VARCHAR        AS (VALUE:team_abbrev::VARCHAR),
    SIDE                               VARCHAR        AS (VALUE:side::VARCHAR),
    DAYS_REST                          NUMBER(38,0)   AS (VALUE:days_rest::NUMBER(38,0)),
    GAMES_LAST_7D                      NUMBER(38,0)   AS (VALUE:games_last_7d::NUMBER(38,0)),
    GAMES_LAST_14D                     NUMBER(38,0)   AS (VALUE:games_last_14d::NUMBER(38,0)),
    IS_HOME_GAME                       BOOLEAN        AS (VALUE:is_home_game::BOOLEAN),
    CONSECUTIVE_HOME_GAMES             NUMBER(38,0)   AS (VALUE:consecutive_home_games::NUMBER(38,0)),
    CONSECUTIVE_AWAY_GAMES             NUMBER(38,0)   AS (VALUE:consecutive_away_games::NUMBER(38,0)),
    TZ_CHANGED_FROM_LAST_GAME          BOOLEAN        AS (VALUE:tz_changed_from_last_game::BOOLEAN),
    TRAVEL_DISTANCE_MILES              FLOAT          AS (VALUE:travel_distance_miles::FLOAT),
    TZ_DELTA_HOURS                     NUMBER(38,0)   AS (VALUE:tz_delta_hours::NUMBER(38,0)),
    IS_3RD_CONSECUTIVE_ROAD_GAME       BOOLEAN        AS (VALUE:is_3rd_consecutive_road_game::BOOLEAN),
    IS_GETAWAY_DAY                     BOOLEAN        AS (VALUE:is_getaway_day::BOOLEAN)
)
WITH LOCATION = @baseball_data.lakehouse_ext.s3_lakehouse/mart_team_schedule_context/
